import { useLang } from '../lib/LangContext.jsx'
import { getCurrentSeason } from '../lib/helpers'
const QATAR = "data:image/png;base64,"
const QPC   = "data:image/png;base64,"
const SIG   = "data:image/png;base64,"

const SEASON = getCurrentSeason().replace('-', ' / ')

const DESIGNATION_AR = {
  'Player': 'لاعب', 'Female Player': 'لاعبة',
  'Coach': 'مدرب', 'Female Coach': 'مدربة',
  'Referee': 'حكم', 'Female Referee': 'حكمة',
  'Admin Staff': 'جهاز إداري', 'Technical Staff': 'جهاز في',
  'Medical Staff': 'جهاز طبي',
  'Board Member': 'عضو مجلس إدارة', 'Female Board Member': 'عضوة مجلس إدارة',
  'Member': 'عضو', 'Female Member': 'عضوة',
  'Employee': 'موظف', 'Female Employee': 'موظفة',
  'Expert': 'خبير في',
}

const RESIDENCY_AR = {
  'Qatari Male': 'قطري', 'Qatari Female': 'قطرية',
  'Resident Male': 'مقيم', 'Resident Female': 'مقيمة',
  'Professional Male': 'محترف', 'Professional Female': 'محترفة',
  'Born in Qatar': 'مواليد قطر', 'Qatari Mother': 'أم قطرية',
}

export function generateAthleteCard(athlete) {
  const desigAr  = DESIGNATION_AR[athlete.designation] || athlete.designation || ''
  const residAr  = RESIDENCY_AR[athlete.residency_status] || athlete.residency_status || ''
  const photoSrc = athlete.photo_url || ''

  const row = (label, value) => `
    <tr>
      <td style="font-size:12px;font-weight:600;color:#000;text-align:right;padding:4px 0;white-space:nowrap;padding-right:8px;width:90px">${label}</td>
      <td style="font-size:13px;color:#111;font-weight:700;text-align:right;padding:4px 0;padding-right:4px">${value || '—'}</td>
    </tr>`

  const html = `<!DOCTYPE html>
<html lang="ar">
<head>
<meta charset="UTF-8"/>
<style>
  * { box-sizing:border-box; margin:0; padding:0; }
  body {
    background:#fff;
    font-family:Arial,sans-serif;
    display:flex;
    flex-direction:column;
    align-items:center;
    gap:6px;
    padding:24px 20px;
  }
  .card {
    width:400px;
    background:#fff;
    border-radius:12px;
    overflow:hidden;
    box-shadow:0 10px 40px rgba(0,0,0,.5), 0 4px 12px rgba(0,0,0,.3);
  }
  @media print {
    body { background:white; padding:0; gap:6mm; }
    .card { box-shadow:none; page-break-inside:avoid; }
    .no-print { display:none !important; }
  }
</style>
</head>
<body>

<!-- FRONT -->
<div class="card">
  <table width="100%" cellpadding="0" cellspacing="0" style="background:#fff">
    <tr>
      <td width="80" style="padding:6px;text-align:center;vertical-align:middle">
        <img src="${QATAR}" width="64" height="70" style="object-fit:contain;display:block;margin:auto"/>
      </td>
      <td style="background:#8B1A1A;text-align:center;vertical-align:middle;padding:8px 4px">
        <div style="color:#fff;font-size:15px;font-weight:bold;line-height:1.6">
          الاتحاد القطري لذوي<br/>الاحتياجات الخاصة
        </div>
      </td>
      <td width="80" style="padding:6px;text-align:center;vertical-align:middle">
        <img src="${QPC}" width="64" height="70" style="object-fit:contain;display:block;margin:auto"/>
      </td>
    </tr>
  </table>

  <div style="text-align:center;font-size:19px;font-weight:bold;color:#000;padding:12px 20px 8px;direction:rtl;width:100%">
    ${athlete.name_ar || athlete.name}
  </div>

  <table width="100%" cellpadding="0" cellspacing="0" style="padding:4px 14px 16px">
    <tr>
      <td width="106" valign="top">
        <div style="width:92px;height:110px;background:#c5d8e4;border-radius:3px;overflow:hidden">
          ${photoSrc
            ? `<img src="${photoSrc}" width="92" height="110" style="object-fit:cover;object-position:top center;display:block"/>`
            : `<div style="width:92px;height:110px;display:flex;align-items:center;justify-content:center;font-size:48px;color:#5b8fa8">👤</div>`
          }
        </div>
        <div style="width:92px;background:#8B1A1A;color:#fff;font-size:14px;font-weight:bold;text-align:center;padding:5px 4px;border-radius:3px;margin-top:7px;letter-spacing:1px">
          ${athlete.qss_number || '00000'}
        </div>
      </td>
      <td valign="top">
        <table width="100%" cellpadding="0" cellspacing="0" style="direction:rtl">
          ${row('النادي', athlete.club || '')}
          ${row('الوظيفة', desigAr)}
          ${row('الفئة', athlete.age_category || '')}
          ${row('الصفة', residAr)}
          ${row('تاريخ الميلاد', athlete.dob || '')}
          ${row('الموسم', SEASON)}
        </table>
      </td>
    </tr>
  </table>
</div>

<!-- BACK -->
<div class="card">
  <div style="background:#8B1A1A;color:#fff;text-align:center;font-size:18px;font-weight:bold;padding:10px;direction:rtl">
    اللجنة الاولمبية القطرية
  </div>
  <div style="padding:18px 16px 24px;background:#fff">
    <table width="100%" cellpadding="0" cellspacing="0" style="margin-bottom:22px">
      <tr>
        <td width="72" valign="middle">
          ${athlete.club_logo
            ? `<img src="${athlete.club_logo}" width="64" height="64" style="object-fit:contain"/>`
            : '<div style="width:64px;height:64px"></div>'
          }
        </td>
        <td valign="middle" style="direction:rtl;padding-right:10px">
          <table cellpadding="0" cellspacing="0" width="100%">
            <tr>
              <td style="font-size:12px;font-weight:600;color:#000;white-space:nowrap;width:90px;padding-right:8px;text-align:right">الرقم الشخصي</td>
              <td style="font-size:15px;font-weight:900;color:#000;direction:ltr;text-align:right;letter-spacing:1px">${athlete.id_number || '—'}</td>
            </tr>
          </table>
        </td>
      </tr>
    </table>
    <div style="text-align:center;font-size:13px;font-weight:bold;color:#111;line-height:1.8;margin-bottom:12px;direction:rtl">
      أمين السر العام للاتحاد القطرى<br/>للاحتياجات الخاصة
    </div>
    <div style="text-align:center">
      <img src="${SIG}" height="52" style="object-fit:contain;display:inline-block"/>
    </div>
  </div>
</div>

<div class="no-print" style="text-align:center;display:flex;gap:12px;justify-content:center;flex-wrap:wrap">
  <button onclick="if(window.opener){window.close();}else{history.back();}" style="padding:10px 28px;background:#555;color:#fff;border:none;border-radius:8px;font-size:14px;cursor:pointer;font-family:Arial">
    ← رجوع / Back
  </button>
  <button onclick="window.print()" style="padding:10px 28px;background:#8B1A1A;color:#fff;border:none;border-radius:8px;font-size:14px;cursor:pointer;font-family:Arial">
    🖨️ طباعة / Print
  </button>
</div>
</body>
</html>`

  return html
}

export default function AthleteCardButton({ athlete }) {
  const { lang } = useLang()
  const ar = lang === 'ar'
  function handleGenerate() {
    const html = generateAthleteCard(athlete)
    const win = window.open('', '_blank')
    win.document.write(html)
    win.document.close()
  }
  return (
    <button onClick={handleGenerate} className="action-btn"
      style={{ borderColor:'#8B1A1A', color:'#8B1A1A', padding:'5px 12px', display:'flex', alignItems:'center', justifyContent:'center', gap:6 }}
      onMouseEnter={e => { e.currentTarget.style.background='#fef2f2' }}
      onMouseLeave={e => { e.currentTarget.style.background='' }}>
      <i className="ti ti-id-badge" style={{ fontSize:14 }} />
      <span>{ar ? 'بطاقة QSS' : 'QSS Card'}</span>
    </button>
  )
}
